// ---- Mini Challenge: Multi-Screen App ----

// ---- Define routes ----
sealed class Screen(val route: String) {
    object Home : Screen("home")
    object Items : Screen("items")
    object Detail : Screen("detail/{itemId}") {
        fun pass(itemId: Int) = "detail/$itemId"
    }
    object AddItem : Screen("add")
}

// ---- Data model ----
data class Item(
    val id: Int,
    val name: String,
    val description: String
)

// ---- App state ----
class AppState {
    private val _items = mutableStateListOf(
        Item(1, "Sword", "A sharp blade"),
        Item(2, "Shield", "A sturdy shield"),
        Item(3, "Potion", "Heals health")
    )
    val items: List<Item> = _items

    fun addItem(name: String, description: String) {
        val id = (_items.maxByOrNull { it.id }?.id ?: 0) + 1
        _items.add(Item(id, name, description))
    }

    fun getItem(id: Int): Item? = _items.find { it.id == id }
}

// ---- Main App ----
@Composable
fun MultiScreenApp() {
    val navController = rememberNavController()
    val appState = remember { AppState() }

    NavHost(
        navController = navController,
        startDestination = Screen.Home.route
    ) {
        composable(Screen.Home.route) {
            HomeScreen(
                onNavigateToItems = { navController.navigate(Screen.Items.route) },
                onNavigateToAdd = { navController.navigate(Screen.AddItem.route) }
            )
        }

        composable(Screen.Items.route) {
            ItemsScreen(
                items = appState.items,
                onItemClick = { itemId ->
                    navController.navigate(Screen.Detail.pass(itemId))
                },
                onBack = { navController.popBackStack() }
            )
        }

        composable(
            route = Screen.Detail.route,
            arguments = listOf(
                navArgument("itemId") { type = NavType.IntType }
            )
        ) { backStackEntry ->
            val itemId = backStackEntry.arguments?.getInt("itemId") ?: 0
            val item = appState.getItem(itemId)
            DetailScreen(
                item = item,
                onBack = { navController.popBackStack() }
            )
        }

        composable(Screen.AddItem.route) {
            AddItemScreen(
                onAddItem = { name, description ->
                    appState.addItem(name, description)
                    navController.popBackStack()
                },
                onCancel = { navController.popBackStack() }
            )
        }
    }
}

// ---- Home Screen ----
@Composable
fun HomeScreen(
    onNavigateToItems: () -> Unit,
    onNavigateToAdd: () -> Unit
) {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Text(
            text = "🏠 Home",
            style = MaterialTheme.typography.headlineLarge
        )
        Button(
            onClick = onNavigateToItems,
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("View Items")
        }
        Button(
            onClick = onNavigateToAdd,
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Add Item")
        }
    }
}

// ---- Items Screen ----
@Composable
fun ItemsScreen(
    items: List<Item>,
    onItemClick: (Int) -> Unit,
    onBack: () -> Unit
) {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp)
    ) {
        Text(
            text = "📋 Items",
            style = MaterialTheme.typography.headlineLarge
        )
        Spacer(modifier = Modifier.height(16.dp))

        LazyColumn(
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            items(items) { item ->
                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clickable { onItemClick(item.id) },
                    elevation = CardDefaults.cardElevation(4.dp)
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp)
                    ) {
                        Text(
                            text = item.name,
                            style = MaterialTheme.typography.titleLarge
                        )
                        Text(
                            text = item.description,
                            style = MaterialTheme.typography.bodyMedium
                        )
                    }
                }
            }
        }

        Button(
            onClick = onBack,
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Back")
        }
    }
}

// ---- Detail Screen ----
@Composable
fun DetailScreen(
    item: Item?,
    onBack: () -> Unit
) {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Text(
            text = "📄 Detail",
            style = MaterialTheme.typography.headlineLarge
        )

        if (item != null) {
            Card(
                modifier = Modifier.fillMaxWidth(),
                elevation = CardDefaults.cardElevation(4.dp)
            ) {
                Column(
                    modifier = Modifier.padding(16.dp),
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    Text(
                        text = item.name,
                        style = MaterialTheme.typography.titleLarge
                    )
                    Text(
                        text = item.description,
                        style = MaterialTheme.typography.bodyLarge
                    )
                    Text(
                        text = "ID: ${item.id}",
                        style = MaterialTheme.typography.bodyMedium,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }
        } else {
            Text("Item not found")
        }

        Button(
            onClick = onBack,
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Back")
        }
    }
}

// ---- Add Item Screen ----
@Composable
fun AddItemScreen(
    onAddItem: (String, String) -> Unit,
    onCancel: () -> Unit
) {
    var name by remember { mutableStateOf("") }
    var description by remember { mutableStateOf("") }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Text(
            text = "➕ Add Item",
            style = MaterialTheme.typography.headlineLarge
        )

        OutlinedTextField(
            value = name,
            onValueChange = { name = it },
            label = { Text("Name") },
            modifier = Modifier.fillMaxWidth()
        )

        OutlinedTextField(
            value = description,
            onValueChange = { description = it },
            label = { Text("Description") },
            modifier = Modifier.fillMaxWidth()
        )

        Button(
            onClick = { onAddItem(name, description) },
            modifier = Modifier.fillMaxWidth(),
            enabled = name.isNotBlank()
        ) {
            Text("Add")
        }

        Button(
            onClick = onCancel,
            modifier = Modifier.fillMaxWidth(),
            colors = ButtonDefaults.buttonColors(
                containerColor = MaterialTheme.colorScheme.error
            )
        ) {
            Text("Cancel")
        }
    }
}

